import React from "react";

export const rawHtml = "{% extends \"crm/crm_base.html\" %}\r\n\r\n{% block crm_title %}Dashboard{% endblock %}\r\n{% block crm_meta_description %}CRM Dashboard - İş süreçlerinizi takip edin{% endblock %}\r\n\r\n{% block crm_extra_css %}\r\n<style>\r\n/* Dashboard Styles */\r\n.stat-card {\r\n  background: white;\r\n  border-radius: 0.5rem;\r\n  box-shadow: 0 1px 3px 0 rgba(0, 0, 0, 0.1);\r\n  border: 1px solid #e5e7eb;\r\n  transition: all 0.2s;\r\n}\r\n\r\n.stat-card:hover {\r\n  box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.1);\r\n  transform: translateY(-1px);\r\n}\r\n\r\n.stat-number {\r\n  font-size: 2.25rem;\r\n  font-weight: 700;\r\n  line-height: 1;\r\n}\r\n\r\n.stat-label {\r\n  font-size: 0.875rem;\r\n  color: #6b7280;\r\n  font-weight: 500;\r\n}\r\n\r\n.chart-container {\r\n  position: relative;\r\n  height: 300px;\r\n  background: white;\r\n  border-radius: 0.5rem;\r\n  box-shadow: 0 1px 3px 0 rgba(0, 0, 0, 0.1);\r\n  border: 1px solid #e5e7eb;\r\n  padding: 1.5rem;\r\n}\r\n\r\n.activity-item {\r\n  padding: 0.75rem;\r\n  border-bottom: 1px solid #f3f4f6;\r\n  transition: background-color 0.2s;\r\n}\r\n\r\n.activity-item:hover {\r\n  background-color: #f9fafb;\r\n}\r\n\r\n.activity-item:last-child {\r\n  border-bottom: none;\r\n}\r\n\r\n/* Loading skeleton */\r\n.skeleton {\r\n  background: linear-gradient(90deg, var(--bg-secondary) 25%, var(--bg-tertiary) 50%, var(--bg-secondary) 75%);\r\n  background-size: 200% 100%;\r\n  animation: loading 1.5s infinite;\r\n  border-radius: 0.375rem;\r\n}\r\n\r\n@keyframes loading {\r\n  0% { background-position: 200% 0; }\r\n  100% { background-position: -200% 0; }\r\n}\r\n\r\n.skeleton-text {\r\n  height: 1rem;\r\n  border-radius: 0.25rem;\r\n  margin-bottom: 0.5rem;\r\n}\r\n\r\n.skeleton-number {\r\n  height: 2.5rem;\r\n  border-radius: 0.25rem;\r\n  margin-bottom: 0.5rem;\r\n}\r\n\r\n.skeleton-avatar {\r\n  width: 2.5rem;\r\n  height: 2.5rem;\r\n  border-radius: 50%;\r\n}\r\n\r\n.skeleton-card {\r\n  height: 6rem;\r\n  border-radius: 0.5rem;\r\n  margin-bottom: 1rem;\r\n}\r\n\r\n/* Smooth transitions */\r\n.fade-in {\r\n  animation: fadeIn 0.3s ease-in;\r\n}\r\n\r\n@keyframes fadeIn {\r\n  from { opacity: 0; transform: translateY(10px); }\r\n  to { opacity: 1; transform: translateY(0); }\r\n}\r\n\r\n.slide-up {\r\n  animation: slideUp 0.4s ease-out;\r\n}\r\n\r\n@keyframes slideUp {\r\n  from { opacity: 0; transform: translateY(20px); }\r\n  to { opacity: 1; transform: translateY(0); }\r\n}\r\n</style>\r\n{% endblock %}\r\n\r\n{% block crm_content %}\r\n<div class=\"mb-6\">\r\n  <div class=\"flex flex-col sm:flex-row sm:items-center sm:justify-between\">\r\n    <div>\r\n      <h2 class=\"text-2xl font-bold text-gray-900 mb-2 flex items-center\">\r\n        <i class=\"fas fa-chart-line mr-3 text-blue-600\"></i>Dashboard\r\n      </h2>\r\n      <p class=\"text-gray-600\">İş süreçlerinizin genel görünümü</p>\r\n    </div>\r\n    <div class=\"mt-4 sm:mt-0\">\r\n      <button id=\"refresh-dashboard\" class=\"btn btn-outline-primary\">\r\n        <i class=\"fas fa-sync-alt mr-2\"></i>Yenile\r\n      </button>\r\n    </div>\r\n  </div>\r\n</div>\r\n\r\n<!-- Stats Cards -->\r\n<div class=\"grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8\">\r\n  <!-- Toplam Kişiler -->\r\n  <div class=\"stat-card p-6\">\r\n    <div class=\"flex items-center\">\r\n      <div class=\"flex-shrink-0\">\r\n        <div class=\"w-12 h-12 bg-blue-100 rounded-lg flex items-center justify-center\">\r\n          <i class=\"fas fa-users text-blue-600 text-xl\"></i>\r\n        </div>\r\n      </div>\r\n      <div class=\"ml-4 flex-1\">\r\n        <div id=\"total-contacts-loading\" class=\"skeleton skeleton-number\" style=\"display: none;\"></div>\r\n        <div id=\"total-contacts\" class=\"stat-number text-blue-600\">-</div>\r\n        <div class=\"stat-label\">Toplam Kişi</div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n\r\n  <!-- Bu Ay Eklenen -->\r\n  <div class=\"stat-card p-6\">\r\n    <div class=\"flex items-center\">\r\n      <div class=\"flex-shrink-0\">\r\n        <div class=\"w-12 h-12 bg-green-100 rounded-lg flex items-center justify-center\">\r\n          <i class=\"fas fa-user-plus text-green-600 text-xl\"></i>\r\n        </div>\r\n      </div>\r\n      <div class=\"ml-4 flex-1\">\r\n        <div id=\"contacts-this-month-loading\" class=\"skeleton skeleton-number\" style=\"display: none;\"></div>\r\n        <div id=\"contacts-this-month\" class=\"stat-number text-green-600\">-</div>\r\n        <div class=\"stat-label\">Bu Ay Eklenen</div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n\r\n  <!-- Toplam Şirketler -->\r\n  <div class=\"stat-card p-6\">\r\n    <div class=\"flex items-center\">\r\n      <div class=\"flex-shrink-0\">\r\n        <div class=\"w-12 h-12 bg-purple-100 rounded-lg flex items-center justify-center\">\r\n          <i class=\"fas fa-building text-purple-600 text-xl\"></i>\r\n        </div>\r\n      </div>\r\n      <div class=\"ml-4 flex-1\">\r\n        <div id=\"total-companies-loading\" class=\"skeleton skeleton-number\" style=\"display: none;\"></div>\r\n        <div id=\"total-companies\" class=\"stat-number text-purple-600\">-</div>\r\n        <div class=\"stat-label\">Toplam Şirket</div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n\r\n  <!-- Dönüşüm Oranı -->\r\n  <div class=\"stat-card p-6\">\r\n    <div class=\"flex items-center\">\r\n      <div class=\"flex-shrink-0\">\r\n        <div class=\"w-12 h-12 bg-orange-100 rounded-lg flex items-center justify-center\">\r\n          <i class=\"fas fa-chart-line text-orange-600 text-xl\"></i>\r\n        </div>\r\n      </div>\r\n      <div class=\"ml-4 flex-1\">\r\n        <div id=\"conversion-rate-loading\" class=\"skeleton skeleton-number\" style=\"display: none;\"></div>\r\n        <div id=\"conversion-rate\" class=\"stat-number text-orange-600\">-%</div>\r\n        <div class=\"stat-label\">Dönüşüm Oranı</div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n</div>\r\n\r\n<!-- Charts Row -->\r\n<div class=\"grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8\">\r\n  <!-- Durum Dağılımı -->\r\n  <div class=\"chart-container\">\r\n    <h3 class=\"text-lg font-semibold text-gray-900 mb-4\">Durum Dağılımı</h3>\r\n    <div id=\"status-chart-loading\" class=\"skeleton\" style=\"height: 200px; display: none;\"></div>\r\n    <canvas id=\"statusChart\" style=\"display: none;\"></canvas>\r\n    <div id=\"status-chart-empty\" class=\"flex items-center justify-center h-48 text-gray-500\" style=\"display: none;\">\r\n      <div class=\"text-center\">\r\n        <i class=\"fas fa-chart-pie text-4xl mb-2\"></i>\r\n        <p>Henüz veri yok</p>\r\n      </div>\r\n    </div>\r\n  </div>\r\n\r\n  <!-- Aylık Trend -->\r\n  <div class=\"chart-container\">\r\n    <h3 class=\"text-lg font-semibold text-gray-900 mb-4\">Son 6 Ay Trend</h3>\r\n    <div id=\"trend-chart-loading\" class=\"skeleton\" style=\"height: 200px; display: none;\"></div>\r\n    <canvas id=\"trendChart\" style=\"display: none;\"></canvas>\r\n    <div id=\"trend-chart-empty\" class=\"flex items-center justify-center h-48 text-gray-500\" style=\"display: none;\">\r\n      <div class=\"text-center\">\r\n        <i class=\"fas fa-chart-line text-4xl mb-2\"></i>\r\n        <p>Henüz veri yok</p>\r\n      </div>\r\n    </div>\r\n  </div>\r\n</div>\r\n\r\n<!-- Recent Activities -->\r\n<div class=\"grid grid-cols-1 lg:grid-cols-3 gap-6\">\r\n  <!-- Son Eklenen Kişiler -->\r\n  <div class=\"bg-white rounded-lg shadow-sm border border-gray-200\">\r\n    <div class=\"px-6 py-4 border-b border-gray-200\">\r\n      <h3 class=\"text-lg font-semibold text-gray-900\">Son Eklenen Kişiler</h3>\r\n    </div>\r\n    <div id=\"recent-contacts-loading\" class=\"p-4\" style=\"display: none;\">\r\n      <div class=\"skeleton skeleton-text\"></div>\r\n      <div class=\"skeleton skeleton-text\"></div>\r\n      <div class=\"skeleton skeleton-text\"></div>\r\n    </div>\r\n    <div id=\"recent-contacts-list\">\r\n      <!-- JavaScript ile doldurulacak -->\r\n    </div>\r\n    <div id=\"recent-contacts-empty\" class=\"p-6 text-center text-gray-500\" style=\"display: none;\">\r\n      <i class=\"fas fa-user-plus text-2xl mb-2\"></i>\r\n      <p>Henüz kişi eklenmemiş</p>\r\n    </div>\r\n  </div>\r\n\r\n  <!-- Son Güncellenen Kişiler -->\r\n  <div class=\"bg-white rounded-lg shadow-sm border border-gray-200\">\r\n    <div class=\"px-6 py-4 border-b border-gray-200\">\r\n      <h3 class=\"text-lg font-semibold text-gray-900\">Son Güncellenen</h3>\r\n    </div>\r\n    <div id=\"updated-contacts-loading\" class=\"p-4\" style=\"display: none;\">\r\n      <div class=\"skeleton skeleton-text\"></div>\r\n      <div class=\"skeleton skeleton-text\"></div>\r\n      <div class=\"skeleton skeleton-text\"></div>\r\n    </div>\r\n    <div id=\"updated-contacts-list\">\r\n      <!-- JavaScript ile doldurulacak -->\r\n    </div>\r\n    <div id=\"updated-contacts-empty\" class=\"p-6 text-center text-gray-500\" style=\"display: none;\">\r\n      <i class=\"fas fa-edit text-2xl mb-2\"></i>\r\n      <p>Henüz güncelleme yok</p>\r\n    </div>\r\n  </div>\r\n\r\n  <!-- Son Etkileşimler -->\r\n  <div class=\"bg-white rounded-lg shadow-sm border border-gray-200\">\r\n    <div class=\"px-6 py-4 border-b border-gray-200\">\r\n      <h3 class=\"text-lg font-semibold text-gray-900\">Son Etkileşimler</h3>\r\n    </div>\r\n    <div id=\"recent-interactions-loading\" class=\"p-4\" style=\"display: none;\">\r\n      <div class=\"skeleton skeleton-text\"></div>\r\n      <div class=\"skeleton skeleton-text\"></div>\r\n      <div class=\"skeleton skeleton-text\"></div>\r\n    </div>\r\n    <div id=\"recent-interactions-list\">\r\n      <!-- JavaScript ile doldurulacak -->\r\n    </div>\r\n    <div id=\"recent-interactions-empty\" class=\"p-6 text-center text-gray-500\" style=\"display: none;\">\r\n      <i class=\"fas fa-comments text-2xl mb-2\"></i>\r\n      <p>Henüz etkileşim yok</p>\r\n    </div>\r\n  </div>\r\n</div>\r\n{% endblock %}\r\n\r\n{% block crm_extra_js %}\r\n<!-- Chart.js CDN -->\r\n<script src=\"https://cdn.jsdelivr.net/npm/chart.js\"></script>\r\n\r\n<script>\r\nclass DashboardManager {\r\n  constructor() {\r\n    this.statusChart = null;\r\n    this.trendChart = null;\r\n    this.refreshBtn = document.getElementById('refresh-dashboard');\r\n    \r\n    this.init();\r\n  }\r\n  \r\n  init() {\r\n    this.bindEvents();\r\n    this.loadDashboard();\r\n  }\r\n  \r\n  bindEvents() {\r\n    if (this.refreshBtn) {\r\n      this.refreshBtn.addEventListener('click', () => {\r\n        this.loadDashboard();\r\n      });\r\n    }\r\n  }\r\n  \r\n  async loadDashboard() {\r\n    this.showLoading();\r\n    \r\n    try {\r\n      // Paralel olarak tüm verileri yükle\r\n      const [statsData, trendData, activitiesData] = await Promise.all([\r\n        this.fetchStats(),\r\n        this.fetchTrendData(),\r\n        this.fetchActivities()\r\n      ]);\r\n      \r\n      this.renderStats(statsData);\r\n      this.renderCharts(statsData, trendData);\r\n      this.renderActivities(activitiesData);\r\n      \r\n    } catch (error) {\r\n      console.error('Dashboard yüklenirken hata:', error);\r\n      this.showError('Dashboard verileri yüklenirken bir hata oluştu.');\r\n    } finally {\r\n      this.hideLoading();\r\n    }\r\n  }\r\n  \r\n  async fetchStats() {\r\n    const response = await fetch('/crm/api/dashboard/stats');\r\n    if (!response.ok) throw new Error(`HTTP error! status: ${response.status}`);\r\n    return await response.json();\r\n  }\r\n  \r\n  async fetchTrendData() {\r\n    const response = await fetch('/crm/api/dashboard/charts/monthly-trend');\r\n    if (!response.ok) throw new Error(`HTTP error! status: ${response.status}`);\r\n    return await response.json();\r\n  }\r\n  \r\n  async fetchActivities() {\r\n    const response = await fetch('/crm/api/dashboard/recent-activities');\r\n    if (!response.ok) throw new Error(`HTTP error! status: ${response.status}`);\r\n    return await response.json();\r\n  }\r\n  \r\n  showLoading() {\r\n    // Stats loading\r\n    document.querySelectorAll('[id$=\"-loading\"]').forEach(el => {\r\n      el.style.display = 'block';\r\n    });\r\n    \r\n    // Hide actual content\r\n    document.getElementById('total-contacts').style.display = 'none';\r\n    document.getElementById('contacts-this-month').style.display = 'none';\r\n    document.getElementById('total-companies').style.display = 'none';\r\n    document.getElementById('conversion-rate').style.display = 'none';\r\n  }\r\n  \r\n  hideLoading() {\r\n    // Hide loading\r\n    document.querySelectorAll('[id$=\"-loading\"]').forEach(el => {\r\n      el.style.display = 'none';\r\n    });\r\n    \r\n    // Show actual content\r\n    document.getElementById('total-contacts').style.display = 'block';\r\n    document.getElementById('contacts-this-month').style.display = 'block';\r\n    document.getElementById('total-companies').style.display = 'block';\r\n    document.getElementById('conversion-rate').style.display = 'block';\r\n  }\r\n  \r\n  renderStats(data) {\r\n    document.getElementById('total-contacts').textContent = data.total_contacts || 0;\r\n    document.getElementById('contacts-this-month').textContent = data.contacts_this_month || 0;\r\n    document.getElementById('total-companies').textContent = data.total_companies || 0;\r\n    document.getElementById('conversion-rate').textContent = `${data.conversion_rate || 0}%`;\r\n  }\r\n\r\n  renderCharts(statsData, trendData) {\r\n    this.renderStatusChart(statsData.status_distribution);\r\n    this.renderTrendChart(trendData);\r\n  }\r\n\r\n  renderStatusChart(statusData) {\r\n    const canvas = document.getElementById('statusChart');\r\n    const loading = document.getElementById('status-chart-loading');\r\n    const empty = document.getElementById('status-chart-empty');\r\n\r\n    loading.style.display = 'none';\r\n\r\n    if (!statusData || statusData.length === 0) {\r\n      empty.style.display = 'flex';\r\n      canvas.style.display = 'none';\r\n      return;\r\n    }\r\n\r\n    empty.style.display = 'none';\r\n    canvas.style.display = 'block';\r\n\r\n    // Destroy existing chart\r\n    if (this.statusChart) {\r\n      this.statusChart.destroy();\r\n    }\r\n\r\n    const ctx = canvas.getContext('2d');\r\n    this.statusChart = new Chart(ctx, {\r\n      type: 'doughnut',\r\n      data: {\r\n        labels: statusData.map(item => item.status || 'Belirtilmemiş'),\r\n        datasets: [{\r\n          data: statusData.map(item => item.count),\r\n          backgroundColor: [\r\n            '#3B82F6', // Blue\r\n            '#10B981', // Green\r\n            '#F59E0B', // Yellow\r\n            '#EF4444', // Red\r\n            '#8B5CF6', // Purple\r\n            '#06B6D4'  // Cyan\r\n          ],\r\n          borderWidth: 2,\r\n          borderColor: '#ffffff'\r\n        }]\r\n      },\r\n      options: {\r\n        responsive: true,\r\n        maintainAspectRatio: false,\r\n        plugins: {\r\n          legend: {\r\n            position: 'bottom',\r\n            labels: {\r\n              padding: 20,\r\n              usePointStyle: true\r\n            }\r\n          }\r\n        }\r\n      }\r\n    });\r\n  }\r\n\r\n  renderTrendChart(trendData) {\r\n    const canvas = document.getElementById('trendChart');\r\n    const loading = document.getElementById('trend-chart-loading');\r\n    const empty = document.getElementById('trend-chart-empty');\r\n\r\n    loading.style.display = 'none';\r\n\r\n    if (!trendData || !trendData.months || trendData.months.length === 0) {\r\n      empty.style.display = 'flex';\r\n      canvas.style.display = 'none';\r\n      return;\r\n    }\r\n\r\n    empty.style.display = 'none';\r\n    canvas.style.display = 'block';\r\n\r\n    // Destroy existing chart\r\n    if (this.trendChart) {\r\n      this.trendChart.destroy();\r\n    }\r\n\r\n    const ctx = canvas.getContext('2d');\r\n    this.trendChart = new Chart(ctx, {\r\n      type: 'line',\r\n      data: {\r\n        labels: trendData.months,\r\n        datasets: [{\r\n          label: 'Eklenen Kişiler',\r\n          data: trendData.counts,\r\n          borderColor: '#3B82F6',\r\n          backgroundColor: 'rgba(59, 130, 246, 0.1)',\r\n          borderWidth: 3,\r\n          fill: true,\r\n          tension: 0.4,\r\n          pointBackgroundColor: '#3B82F6',\r\n          pointBorderColor: '#ffffff',\r\n          pointBorderWidth: 2,\r\n          pointRadius: 6\r\n        }]\r\n      },\r\n      options: {\r\n        responsive: true,\r\n        maintainAspectRatio: false,\r\n        plugins: {\r\n          legend: {\r\n            display: false\r\n          }\r\n        },\r\n        scales: {\r\n          y: {\r\n            beginAtZero: true,\r\n            ticks: {\r\n              stepSize: 1\r\n            }\r\n          }\r\n        }\r\n      }\r\n    });\r\n  }\r\n\r\n  renderActivities(data) {\r\n    this.renderRecentContacts(data.recent_contacts);\r\n    this.renderUpdatedContacts(data.updated_contacts);\r\n    this.renderRecentInteractions(data.recent_interactions);\r\n  }\r\n\r\n  renderRecentContacts(contacts) {\r\n    const container = document.getElementById('recent-contacts-list');\r\n    const loading = document.getElementById('recent-contacts-loading');\r\n    const empty = document.getElementById('recent-contacts-empty');\r\n\r\n    loading.style.display = 'none';\r\n\r\n    if (!contacts || contacts.length === 0) {\r\n      empty.style.display = 'block';\r\n      container.innerHTML = '';\r\n      return;\r\n    }\r\n\r\n    empty.style.display = 'none';\r\n    container.innerHTML = contacts.map(contact => `\r\n      <div class=\"activity-item\">\r\n        <div class=\"flex items-center\">\r\n          <div class=\"flex-shrink-0\">\r\n            <div class=\"w-8 h-8 bg-blue-100 rounded-full flex items-center justify-center\">\r\n              <span class=\"text-xs font-medium text-blue-600\">\r\n                ${(contact.name.split(' ')[0]?.[0] || '?') + (contact.name.split(' ')[1]?.[0] || '')}\r\n              </span>\r\n            </div>\r\n          </div>\r\n          <div class=\"ml-3 flex-1\">\r\n            <p class=\"text-sm font-medium text-gray-900\">\r\n              <a href=\"/crm/contact/${contact.id}\" class=\"hover:text-blue-600\">\r\n                ${contact.name}\r\n              </a>\r\n            </p>\r\n            <p class=\"text-xs text-gray-500\">${contact.email || 'Email yok'}</p>\r\n            <p class=\"text-xs text-gray-400\">\r\n              ${new Date(contact.created_at).toLocaleDateString('tr-TR')}\r\n            </p>\r\n          </div>\r\n          <div class=\"flex-shrink-0\">\r\n            <span class=\"inline-flex px-2 py-1 text-xs font-semibold rounded-full bg-blue-100 text-blue-800\">\r\n              ${contact.status || 'Lead'}\r\n            </span>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    `).join('');\r\n  }\r\n\r\n  renderUpdatedContacts(contacts) {\r\n    const container = document.getElementById('updated-contacts-list');\r\n    const loading = document.getElementById('updated-contacts-loading');\r\n    const empty = document.getElementById('updated-contacts-empty');\r\n\r\n    loading.style.display = 'none';\r\n\r\n    if (!contacts || contacts.length === 0) {\r\n      empty.style.display = 'block';\r\n      container.innerHTML = '';\r\n      return;\r\n    }\r\n\r\n    empty.style.display = 'none';\r\n    container.innerHTML = contacts.map(contact => `\r\n      <div class=\"activity-item\">\r\n        <div class=\"flex items-center\">\r\n          <div class=\"flex-shrink-0\">\r\n            <div class=\"w-8 h-8 bg-green-100 rounded-full flex items-center justify-center\">\r\n              <i class=\"fas fa-edit text-green-600 text-xs\"></i>\r\n            </div>\r\n          </div>\r\n          <div class=\"ml-3 flex-1\">\r\n            <p class=\"text-sm font-medium text-gray-900\">\r\n              <a href=\"/crm/contact/${contact.id}\" class=\"hover:text-blue-600\">\r\n                ${contact.name}\r\n              </a>\r\n            </p>\r\n            <p class=\"text-xs text-gray-500\">${contact.email || 'Email yok'}</p>\r\n            <p class=\"text-xs text-gray-400\">\r\n              ${new Date(contact.updated_at).toLocaleDateString('tr-TR')}\r\n            </p>\r\n          </div>\r\n          <div class=\"flex-shrink-0\">\r\n            <span class=\"inline-flex px-2 py-1 text-xs font-semibold rounded-full bg-green-100 text-green-800\">\r\n              Güncellendi\r\n            </span>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    `).join('');\r\n  }\r\n\r\n  renderRecentInteractions(interactions) {\r\n    const container = document.getElementById('recent-interactions-list');\r\n    const loading = document.getElementById('recent-interactions-loading');\r\n    const empty = document.getElementById('recent-interactions-empty');\r\n\r\n    loading.style.display = 'none';\r\n\r\n    if (!interactions || interactions.length === 0) {\r\n      empty.style.display = 'block';\r\n      container.innerHTML = '';\r\n      return;\r\n    }\r\n\r\n    empty.style.display = 'none';\r\n    container.innerHTML = interactions.map(interaction => `\r\n      <div class=\"activity-item\">\r\n        <div class=\"flex items-center\">\r\n          <div class=\"flex-shrink-0\">\r\n            <div class=\"w-8 h-8 bg-purple-100 rounded-full flex items-center justify-center\">\r\n              <i class=\"fas fa-comments text-purple-600 text-xs\"></i>\r\n            </div>\r\n          </div>\r\n          <div class=\"ml-3 flex-1\">\r\n            <p class=\"text-sm font-medium text-gray-900\">${interaction.type}</p>\r\n            <p class=\"text-xs text-gray-600\">${interaction.contact_name}</p>\r\n            <p class=\"text-xs text-gray-500 truncate\">${interaction.summary}</p>\r\n            <p class=\"text-xs text-gray-400\">\r\n              ${new Date(interaction.interaction_date).toLocaleDateString('tr-TR')}\r\n            </p>\r\n          </div>\r\n        </div>\r\n      </div>\r\n    `).join('');\r\n  }\r\n\r\n  showError(message) {\r\n    console.error(message);\r\n    // Burada toast notification gösterilebilir\r\n  }\r\n}\r\n\r\n// Sayfa yüklendiğinde başlat\r\ndocument.addEventListener('DOMContentLoaded', () => {\r\n  new DashboardManager();\r\n});\r\n</script>\r\n{% endblock %}\r\n";

export default function CrmDashboard(props: { html?: string; wrapperClassName?: string }) {
  const { html = rawHtml, wrapperClassName } = props;
  return (
    <div className={wrapperClassName} dangerouslySetInnerHTML={{ __html: html }} />
  );
}
